const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let n = input[j * 2][0];
            let k = input[j * 2][1];
            let arr = input[j * 2 + 1];
            arr.sort((a, b) => a - b);
            let count = 0;
            for (let l = 0; l < n; l++) {
                if (arr[l] < k) {
                    count++;
                }
            }
            console.log(count);
        }
    }
});

